.darma-loader-uiverse-crimson-triple-glide { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.darma-loader-uiverse-crimson-triple-glide__mover {
  background: color-mix(in srgb, var(--loader-color, #f81919) 98%, transparent);
  height: 10px;
  width: 80px;
  border-radius: 10px;
  position: relative;
  animation: darma-loader-uiverse-crimson-triple-glide-mover5 2s ease-in-out infinite;
}

.darma-loader-uiverse-crimson-triple-glide__mover::before,
.darma-loader-uiverse-crimson-triple-glide__mover::after {
content: '';
position: absolute;
height: 10px;
border-radius: 10px;
left: 20px;
animation: darma-loader-uiverse-crimson-triple-glide-mover5 2s ease-in-out infinite;
}

.darma-loader-uiverse-crimson-triple-glide__mover::before {
background: rgb(201, 1, 1);
top: 20px;
width: 50px;
}

.darma-loader-uiverse-crimson-triple-glide__mover::after {
background: var(--loader-secondary-color, #ff746a);
top: -20px;
width: 60px;
}

@keyframes darma-loader-uiverse-crimson-triple-glide-mover5 {
0% {
transform: translateX(30px) scale(1);
}

50% {
transform: translateX(-30px) scale(1.1);
}

100% {
transform: translateX(30px) scale(1);
}
}

